// src/reasoningExtractor.ts
var DEFAULT_REASONING_MARKERS = [
  { start: "<think>", end: "</think>" },
  { start: "<reasoning>", end: "</reasoning>" },
  { start: "<thought>", end: "</thought>" }
];
function extractActualResponse(content, markers) {
  let result = content;
  for (const marker of markers) {
    const startEsc = marker.start.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const endEsc = marker.end.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const regex2 = new RegExp(`${startEsc}[\\s\\S]*?${endEsc}`, "g");
    result = result.replace(regex2, "");
  }
  return result.trimStart();
}
function parseReasoningMarkers(json) {
  try {
    const parsed = JSON.parse(json);
    if (Array.isArray(parsed) && parsed.every((m) => m.start && m.end)) {
      return parsed;
    }
  } catch (e) {
  }
  return DEFAULT_REASONING_MARKERS;
}

